@using sv_ea3fa1b524bd43f49ab52e3344ce820f

<div class="task-card">
    <h4 class="task-title">@Task.Title</h4>
    <p class="task-assignee">@Task.Assignee</p>
    <span class="badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    <span class="task-due">@Task.DueDate.ToString("MMM dd")</span>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn btn-sm btn-outline" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn btn-sm btn-outline" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
}

@using sv_ea3fa1b524bd43f49ab52e3344ce820f

@if (!IsVisible)
{
    <button class="btn btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <div class="form-group">
            <label>Title</label>
            <input type="text" @bind="title" placeholder="Task title" />
        </div>
        <div class="form-group">
            <label>Assignee</label>
            <input type="text" @bind="assignee" placeholder="Assignee name" />
        </div>
        <div class="form-group">
            <label>Priority</label>
            <select @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="form-group">
            <label>Due Date</label>
            <input type="date" @bind="dueDate" />
        </div>
        <div class="form-actions">
            <button class="btn btn-save" @onclick="Save" disabled="@isSaving">Save</button>
            <button class="btn btn-cancel" @onclick="Cancel" disabled="@isSaving">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            await OnTaskCreated.InvokeAsync(
                new TaskItem(0, title.Trim(), assignee.Trim(), priority, dueDate, Status));
            ResetForm();
            IsVisible = false;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

