<div class="kanban-column">
    <div class="column-header">
        <h3>@Title <span class="column-count">(@Tasks.Count)</span></h3>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="CanMoveLeft"
                      ShowMoveRight="CanMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>
    <div class="column-footer">
        <AddTaskForm Status="@Status" OnTaskCreated="OnTaskCreated" />
    </div>
</div>

