toolArgs.file_text:
@page "/board"
@using sv_ea3fa1b524bd43f49ab52e3344ce820f
@using sv_ea3fa1b524bd43f49ab52e3344ce820f.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <p class="board-loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button class="btn" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummary Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="kanban-board">
        <KanbanColumn Title="To Do" Status="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      CanMoveLeft="false" CanMoveRight="true"
                      OnMoveRight="id => MoveTask(id, "In Progress")"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn Title="In Progress" Status="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      CanMoveLeft="true" CanMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, "To Do")"
                      OnMoveRight="id => MoveTask(id, "Done")"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn Title="Done" Status="Done"
                      Tasks="GetFilteredTasks("Done")"
                      CanMoveLeft="true" CanMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, "In Progress")"
                      OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                var index = allTasks.IndexOf(task);
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated(TaskItem formData)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

